import pytest

@pytest.fixture
def database():
    conn = create_connection()
    yield conn        # test receives conn here
    conn.close()      # always runs after the test


@pytest.fixture
def redis_client():
    client = redis.Redis(host="localhost", port=6379, db=15)
    client.flushdb()  # clean before test
    yield client
    client.flushdb()  # clean after test
    client.close()


def test_query(database):
    result = database.execute("SELECT 1")
    assert result == 1

@pytest.fixture def user_factory(db): """Factory for creating users with customizable attributes.""" created_users = []
def create( email: str | None = None, name: str = "Test User", is_active: bool = True, **kwargs, ): if email is None: email = f"user{len(created_users) + 1}@example.com" user = User.objects.create( email=email, name=name, is_active=is_active, **kwargs ) created_users.append(user) return user
return create
def test_user_list_returns_active_users(user_factory): active_user = user_factory(is_active=True) inactive_user = user_factory(is_active=False)
result = UserService.list_active_users()
assert active_user in result assert inactive_user not in result

@pytest.fixture
def user(user_factory):
    """A default user for tests that need a single user."""
    return user_factory()


@pytest.fixture
def admin_user(user_factory):
    """An admin user."""
    return user_factory(email="admin@example.com", is_admin=True)


@pytest.fixture
def team(user_factory, team_factory):
    """A team with owner and two members."""
    owner = user_factory(email="owner@example.com")
    team = team_factory(owner=owner)
    team.add_member(user_factory(email="member1@example.com"))
    team.add_member(user_factory(email="member2@example.com"))
    return team
